{
  "executive_summary": "Integration architecture for a logistics platform connecting three external systems (SAP ERP via SFTP/XML, DHL Carrier API via REST/webhooks, Analytics via Kafka) using an event-driven backbone with dedicated Anti-Corruption Layers per integration. The design isolates each external system behind adapter boundaries, routes all domain events through an internal event bus, and uses outbound processors to translate and deliver events in each system's native protocol and format.",

  "architecture": {
    "components": [
      {
        "name": "Internal Event Bus",
        "responsibility": "Central backbone for all domain events (OrderPlaced, OrderConfirmed, ShipmentCreated, DeliveryAttempted, DeliveryCompleted, DeliveryFailed). Single source of truth for event flow within the platform.",
        "boundaries": "Owns the canonical event schema. All components publish to and subscribe from this bus. Implemented as an internal Kafka topic partition scheme or equivalent durable message broker."
      },
      {
        "name": "SAP ERP Adapter (System A ACL)",
        "responsibility": "Subscribes to OrderConfirmed events from the internal bus. Transforms canonical events into SAP-compliant XML. Batches and writes XML files to SFTP on a 15-minute schedule. Handles SFTP connection failures with retry and dead-letter. Maintains an outbox table for guaranteed delivery.",
        "boundaries": "Owns XML schema mapping and SFTP connection management. No SAP-specific concerns leak into the core domain. Operates on a scheduled cadence, not real-time."
      },
      {
        "name": "DHL Carrier Adapter (System B ACL)",
        "responsibility": "Outbound: translates ShipmentCreated events into DHL REST API calls to book shipments. Inbound: receives DHL webhook callbacks for status updates, translates them into domain events (DeliveryAttempted, DeliveryCompleted, DeliveryFailed), and publishes to the internal event bus.",
        "boundaries": "Owns DHL API client, webhook endpoint, request/response mapping, and rate limiting. Webhook handler must respond within 500ms — does minimal validation and immediately enqueues for async processing. DHL-specific data models never cross this boundary."
      },
      {
        "name": "DHL Webhook Ingress",
        "responsibility": "Lightweight HTTP endpoint that receives DHL webhook callbacks, validates signatures, persists the raw payload to a fast queue, and returns 200 within the 500ms SLA. Decoupled from domain event translation.",
        "boundaries": "Owns only HTTP reception and raw payload persistence. No business logic. Optimized for latency."
      },
      {
        "name": "Analytics Stream Publisher (System C ACL)",
        "responsibility": "Subscribes to ALL domain events on the internal bus. Transforms them into the analytics platform's expected event schema and publishes to the external Kafka topic(s) in real-time.",
        "boundaries": "Owns analytics schema mapping and external Kafka producer configuration. Handles schema evolution via a schema registry. Does not filter events — publishes the full stream."
      },
      {
        "name": "Outbox Processor",
        "responsibility": "Implements the transactional outbox pattern. Ensures domain events are atomically written with state changes and reliably published to the internal event bus. Prevents lost events on crashes.",
        "boundaries": "Sits between the core domain's persistence layer and the internal event bus. Polls or uses CDC to relay events."
      },
      {
        "name": "Core Domain Service",
        "responsibility": "Processes order and delivery lifecycle logic. Emits domain events as side effects of state transitions. Contains all business rules and invariants.",
        "boundaries": "Has zero knowledge of external systems. Depends only on domain abstractions (repository interfaces, event publisher interface)."
      }
    ],
    "interfaces": [
      {
        "from": "Core Domain Service",
        "to": "Internal Event Bus",
        "contract": "Publishes domain events (OrderPlaced, OrderConfirmed, ShipmentCreated, DeliveryAttempted, DeliveryCompleted, DeliveryFailed) via transactional outbox. Events carry: eventId (UUID), eventType, aggregateId, timestamp, payload.",
        "coupling_type": "loose — fire-and-forget publish, no response expected"
      },
      {
        "from": "Internal Event Bus",
        "to": "SAP ERP Adapter",
        "contract": "Adapter subscribes to OrderConfirmed events. Consumes at its own pace with consumer-group offset tracking. Idempotent processing keyed on eventId.",
        "coupling_type": "loose — async subscription, temporal decoupling via 15-min batch window"
      },
      {
        "from": "SAP ERP Adapter",
        "to": "SAP SFTP Server",
        "contract": "XML files conforming to SAP IDoc/EDI schema, written to a designated SFTP directory. File naming convention includes batch timestamp and sequence number for idempotency.",
        "coupling_type": "loose — file-based, no synchronous dependency"
      },
      {
        "from": "Internal Event Bus",
        "to": "DHL Carrier Adapter",
        "contract": "Adapter subscribes to ShipmentCreated events. Translates to DHL Shipment Booking API calls (POST /shipments). Handles 4xx/5xx with exponential backoff and circuit breaker.",
        "coupling_type": "moderate — outbound REST call creates temporal coupling with DHL API availability"
      },
      {
        "from": "DHL Webhook Ingress",
        "to": "DHL Carrier Adapter",
        "contract": "Raw webhook payloads enqueued to an internal fast queue (in-memory or Redis stream). Adapter picks up, validates, maps to domain events, publishes to internal bus.",
        "coupling_type": "loose — async handoff via queue ensures webhook latency SLA is met"
      },
      {
        "from": "Internal Event Bus",
        "to": "Analytics Stream Publisher",
        "contract": "Publisher subscribes to ALL event types. Transforms to analytics schema (Avro/JSON with schema registry). Publishes to external Kafka topic with at-least-once delivery.",
        "coupling_type": "loose — async event stream, analytics platform is a pure consumer"
      }
    ],
    "data_flow": "Core Domain emits events → Transactional Outbox ensures durability → Internal Event Bus distributes → Three ACL adapters consume independently: (A) SAP Adapter batches OrderConfirmed into XML and writes to SFTP every 15min, (B) DHL Adapter calls REST API for ShipmentCreated and receives webhook callbacks via a fast ingress endpoint that enqueues for async domain event translation, (C) Analytics Publisher streams all events to external Kafka in real-time. Inbound DHL webhooks flow: HTTP → Webhook Ingress (fast ack) → Internal Queue → DHL Adapter (translate) → Internal Event Bus → all subscribers including Analytics.",
    "patterns_used": [
      {
        "pattern": "Anti-Corruption Layer (per integration)",
        "rationale": "Each external system has a wildly different protocol (SFTP/XML, REST/webhook, Kafka), data model, and temporal coupling. ACLs prevent any external model from polluting the core domain and allow each integration to evolve independently."
      },
      {
        "pattern": "Transactional Outbox",
        "rationale": "Guarantees that domain state changes and event publication are atomic. Prevents lost events if the broker is temporarily unavailable. Critical for a logistics platform where a missed OrderConfirmed could mean an order never reaches SAP."
      },
      {
        "pattern": "Event-Driven Architecture (internal event bus)",
        "rationale": "All three integrations need different subsets of the same domain events. A central event bus provides fan-out without point-to-point coupling. Adding a fourth integration requires zero changes to existing components."
      },
      {
        "pattern": "Async Webhook Ingress (CQRS-lite)",
        "rationale": "DHL's 500ms webhook SLA demands that the HTTP handler does minimal work. Separating reception (fast ack) from processing (domain translation) ensures the SLA is met even under load spikes or transient downstream issues."
      },
      {
        "pattern": "Circuit Breaker (on DHL outbound calls)",
        "rationale": "DHL REST API is the one synchronous external dependency. Circuit breaker prevents cascade failure and allows graceful degradation when DHL is unavailable."
      },
      {
        "pattern": "Batch Outbound Processor (SAP)",
        "rationale": "SAP expects files every 15 minutes, not real-time. Batching aligns with the downstream system's consumption model and reduces SFTP overhead."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Fulfillment (Core Domain)",
        "classification": "core",
        "aggregates": ["Order (states: Placed → Confirmed → Shipped → Delivered/Failed)", "Shipment (states: Created → InTransit → Delivered/Failed)"]
      },
      {
        "name": "ERP Integration",
        "classification": "generic",
        "aggregates": ["ERPExportBatch (tracks which OrderConfirmed events have been batched and transmitted)"]
      },
      {
        "name": "Carrier Integration",
        "classification": "supporting",
        "aggregates": ["CarrierShipmentBooking (tracks outbound booking state and correlates with webhook callbacks)"]
      },
      {
        "name": "Analytics Integration",
        "classification": "generic",
        "aggregates": ["EventProjection (stateless — pure event transformation, no aggregate state needed)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Fulfillment",
        "downstream": "ERP Integration",
        "relationship": "Customer-Supplier — Order Fulfillment publishes events; ERP Integration consumes and transforms. ERP adapter conforms to the core domain's event schema but owns its own XML mapping."
      },
      {
        "upstream": "Order Fulfillment",
        "downstream": "Carrier Integration",
        "relationship": "Customer-Supplier with ACL — Carrier Integration translates bidirectionally. Outbound: core events → DHL API. Inbound: DHL webhooks → core events. ACL prevents DHL's model from leaking upstream."
      },
      {
        "upstream": "Order Fulfillment",
        "downstream": "Analytics Integration",
        "relationship": "Open Host Service / Published Language — Core domain publishes a well-defined event stream. Analytics Integration is a conformist consumer that maps to the analytics schema."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Internal Kafka as event bus rather than a simpler in-process event emitter",
      "gains": "Durability, replay capability, independent consumer scaling, natural fit with the external Kafka requirement for analytics",
      "sacrifices": "Operational complexity of running Kafka, added latency for in-process events (~low single-digit ms)",
      "alternatives_considered": ["In-process event bus (too fragile for cross-system guarantees)", "RabbitMQ (viable but adds a second messaging technology since analytics already requires Kafka)", "AWS EventBridge (viable if cloud-native, but adds vendor lock-in)"]
    },
    {
      "decision": "Separate Webhook Ingress from DHL Adapter processing",
      "gains": "Guarantees 500ms webhook SLA independent of processing complexity. Enables independent scaling of ingress vs processing.",
      "sacrifices": "Adds an intermediate queue and a small delay before domain events are emitted from inbound webhooks",
      "alternatives_considered": ["Synchronous processing in webhook handler (risky — any slowdown violates SLA)", "Lambda/serverless for webhook ingress (viable but may introduce cold-start latency)"]
    },
    {
      "decision": "Transactional outbox over dual-write (DB + event bus)",
      "gains": "Atomicity guarantee — no lost events, no phantom events. Battle-tested pattern for exactly this problem.",
      "sacrifices": "Slight added complexity in the persistence layer. Outbox polling adds small latency (mitigated with CDC).",
      "alternatives_considered": ["Dual-write with saga compensation (complex and error-prone)", "Event sourcing (powerful but high adoption cost if not already in use)"]
    },
    {
      "decision": "One ACL per external system rather than a shared integration layer",
      "gains": "Each integration evolves independently. A change to DHL's API has zero impact on SAP or analytics. Teams can own integrations independently.",
      "sacrifices": "Some structural duplication across adapters (e.g., each has its own event consumer setup)",
      "alternatives_considered": ["Shared ESB/integration bus (creates a central coupling point and governance bottleneck)"]
    }
  ],

  "flexibility_points": [
    {
      "area": "Adding new external integrations",
      "evolution_path": "New systems subscribe to the internal event bus via a new ACL adapter. Zero changes to core domain or existing adapters. Example: adding a warehouse management system is a new subscriber + adapter."
    },
    {
      "area": "Replacing the carrier (DHL → FedEx)",
      "evolution_path": "Implement a new Carrier Adapter with FedEx-specific API client and webhook handler. Core domain's ShipmentCreated event contract is unchanged. Can run both adapters in parallel during migration."
    },
    {
      "area": "Changing SAP batch frequency",
      "evolution_path": "SAP Adapter's batch schedule is a configuration value, not architectural. Changing from 15-min to 5-min or real-time requires only adapter-level changes."
    },
    {
      "area": "Adding new domain events",
      "evolution_path": "New events are added to the canonical schema and published to the bus. Each adapter independently decides whether to handle the new event type. No breaking changes."
    }
  ],

  "rigidity_points": [
    {
      "area": "Canonical domain event schema",
      "reason": "All three integrations and the core domain depend on this contract. Breaking changes require coordinated migration across all adapters. This is intentional rigidity — the event schema IS the platform's API. Use schema versioning and backward-compatible evolution."
    },
    {
      "area": "Internal Event Bus technology choice (Kafka)",
      "reason": "Once Kafka is the backbone, switching to a different broker is a large migration. Acceptable because Kafka is already required for the analytics integration, so it's not an additional technology bet."
    },
    {
      "area": "Transactional outbox coupling to the persistence layer",
      "reason": "The outbox pattern ties event publication to the database transaction model. Switching from relational DB to a non-transactional store would require rethinking this pattern."
    }
  ],

  "risks": [
    {
      "risk": "DHL webhook ingress becomes a bottleneck under high delivery volume, causing 500ms SLA breaches",
      "severity": "high",
      "mitigation": "Deploy webhook ingress as a stateless, horizontally scalable service. Use an in-memory queue (Redis Streams) for fast enqueue. Load test at 10x expected peak. Set up latency alarms at p95 > 300ms."
    },
    {
      "risk": "SAP SFTP connection failures cause a growing backlog of undelivered order confirmations",
      "severity": "high",
      "mitigation": "Outbox tracks delivery state per batch. Exponential backoff retry with alerting after 3 consecutive failures. Dead-letter mechanism for manual intervention. Monitor batch lag (time since last successful delivery)."
    },
    {
      "risk": "Event ordering issues — analytics platform receives events out of order (e.g., DeliveryCompleted before ShipmentCreated)",
      "severity": "medium",
      "mitigation": "Partition Kafka topics by aggregateId (orderId/shipmentId) to guarantee per-entity ordering. Analytics adapter should handle late-arriving events gracefully."
    },
    {
      "risk": "DHL webhook payload format changes without notice, causing silent data loss",
      "severity": "medium",
      "mitigation": "Webhook ingress persists raw payloads before any parsing. DHL Adapter validates payloads against an expected schema and routes unparseable payloads to a dead-letter queue with alerting."
    },
    {
      "risk": "Outbox processor lag causes stale data in all downstream systems simultaneously",
      "severity": "medium",
      "mitigation": "Use CDC (Debezium) instead of polling for near-zero lag. Monitor outbox table size and processing lag. Alert if lag exceeds 5 seconds."
    },
    {
      "risk": "Duplicate events cause duplicate shipment bookings at DHL (financial impact)",
      "severity": "critical",
      "mitigation": "DHL Adapter must be idempotent. Use eventId as an idempotency key. Maintain a processed-event ledger. DHL API likely supports idempotency keys — use them."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Implement in three phases: Phase 1 — Core event infrastructure (internal Kafka bus, transactional outbox, canonical event schema). Phase 2 — Adapters in parallel: SAP batch exporter, DHL bidirectional adapter with webhook ingress, Analytics stream publisher. Phase 3 — Observability and resilience (circuit breakers, dead-letter queues, lag monitoring, alerting). Start with the DHL adapter as it has the tightest SLA constraint (500ms) and bidirectional complexity.",
    "files_to_create_or_modify": [
      "src/core/events/ — canonical event types and schema definitions",
      "src/core/outbox/ — transactional outbox implementation (OutboxEntry entity, OutboxProcessor)",
      "src/integrations/sap/ — SAP ACL: event consumer, XML mapper, SFTP client, batch scheduler",
      "src/integrations/dhl/ — DHL ACL: REST client, webhook ingress controller, webhook processor, domain event translator",
      "src/integrations/analytics/ — Analytics ACL: event consumer, schema transformer, external Kafka producer",
      "src/infrastructure/kafka/ — internal Kafka producer/consumer configuration, topic definitions",
      "src/infrastructure/resilience/ — circuit breaker, retry policies, dead-letter queue handlers",
      "config/ — per-environment configuration for SFTP credentials, DHL API keys, Kafka broker addresses, batch schedules"
    ],
    "patterns_to_follow": "Each adapter follows the same structural pattern: EventConsumer → Translator → ExternalClient. Inbound adapters (DHL webhook) follow: HttpController → RawPersistence → Translator → EventPublisher. All adapters are independently deployable and testable. Use ports-and-adapters (hexagonal) architecture within the core domain.",
    "pitfalls_to_avoid": [
      "Do NOT let DHL or SAP data models appear in the core domain — always translate at the boundary",
      "Do NOT process DHL webhooks synchronously in the HTTP handler — the 500ms SLA leaves no room for business logic",
      "Do NOT use a shared database between the core domain and integration adapters — each adapter manages its own state",
      "Do NOT rely on message ordering across different aggregate IDs — only partition-level ordering is guaranteed in Kafka",
      "Do NOT skip idempotency on the DHL outbound calls — duplicate shipment bookings have financial consequences",
      "Do NOT build a single monolithic integration service — keep adapters separate so a DHL outage doesn't affect SAP delivery"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 82,
    "high_confidence_areas": [
      "ACL-per-integration is the correct boundary pattern — the three systems have incompatible protocols, models, and temporal requirements",
      "Event-driven backbone with Kafka — natural fit given the analytics requirement and fan-out to three consumers",
      "Transactional outbox for reliable event publication — well-established pattern for this exact problem",
      "Async webhook ingress — necessary to meet the 500ms SLA given unpredictable processing complexity"
    ],
    "low_confidence_areas": [
      "Internal Kafka vs reusing the analytics Kafka cluster — depends on operational constraints and whether the analytics Kafka is managed externally",
      "Exact retry and backoff parameters for SFTP and DHL — need production traffic patterns to tune",
      "Whether CDC (Debezium) or polling is appropriate for the outbox — depends on the database technology in use"
    ],
    "assumptions": [
      "The logistics platform uses a relational database that supports transactions (for the outbox pattern)",
      "Kafka is acceptable as the internal event bus technology (not just for the analytics export)",
      "DHL webhooks support signature verification for authentication",
      "SAP expects standard IDoc or EDI XML format via SFTP (not a custom schema)",
      "The platform is deployed in an environment that supports multiple independently scalable services"
    ]
  }
}

